INSERT INTO authors (author_id, name, bio, photo_url) VALUES
(1, 'হুমায়ূন আহমেদ', 'বাংলা সাহিত্যের এক কিংবদন্তী হুমায়ূন আহমেদ। বিংশ শতাব্দীর বাঙালি লেখকদের মধ্যে তিনি অন্যতম স্থান দখল করে আছেন। একাধারে ঔপন্যাসিক, ছোটগল্পকার ও নাট্যকার এ মানুষটিকে বলা হয় বাংলা সায়েন্স ফিকশনের পথিকৃৎ। নাটক ও চলচ্চিত্র পরিচালক হিসেবেও তিনি বেশ সমাদৃত। বাদ যায়নি গীতিকার কিংবা চিত্রশিল্পীর পরিচয়ও। সৃজনশীলতার প্রতিটি শাখায় তাঁর সমান বিচরণ ছিল। অর্জন করেছেন সর্বোচ্চ সফলতা এবং তুমুল জনপ্রিয়তা। স্বাধীনতা পরবর্তী বাঙালি জাতিকে হুমায়ুন আহমেদ উপহার দিয়েছেন তাঁর অসামান্য বই, নাটক এবং চলচ্চিত্র। ১৯৪৮ সালের ১৩ই নভেম্বর নেত্রকোনা জেলার কুতুবপুরে জন্মগ্রহণ করেন এবং ২০১২ সালে তিনি ইহলোক ত্যাগ করেন।', ''),
(2, 'সমরেশ মজুমদার', 'বাংলা সাহিত্যের অন্যতম শ্রেষ্ঠ রূপকার সমরেশ মজুমদার। তাঁর লেখনীতে উঠে এসেছে রাজনীতি, প্রেম ও সমাজের নানা অসংগতি এবং নকশাল আন্দোলনের প্রেক্ষাপট। ''উত্তরাধিকার'', ''কালবেলা'' ও ''কালপুরুষ'' ট্রিলজির মাধ্যমে তিনি অমর হয়ে আছেন। ১৯৪৪ সালের ১০ মার্চ জলপাইগুড়িতে জন্মগ্রহণ করেন তিনি। ২০২৩ সালের ৮ মে তিনি কলকাতায় শেষ নিঃশ্বাস ত্যাগ করেন।', ''),
(3, 'রবীন্দ্রনাথ ঠাকুর', 'বাংলা সাহিত্যের সর্বশ্রেষ্ঠ প্রতিভা এবং বিশ্বকবি রবীন্দ্রনাথ ঠাকুর। তিনি একাধারে কবি, ঔপন্যাসিক, গল্পকার, গীতিকার, সুরকার, নাট্যকার ও চিত্রশিল্পী। ১৯১৩ সালে ''গীতাঞ্জলি'' কাব্যগ্রন্থের জন্য তিনি সাহিত্যে নোবেল পুরস্কার অর্জন করেন। ১৮৬১ সালের ৭ই মে কলকাতার জোড়াসাঁকো ঠাকুরবাড়িতে তিনি জন্মগ্রহণ করেন এবং ১৯৪১ সালে পরলোকগমন করেন।', ''),
(4, 'সুনীল গঙ্গোপাধ্যায়', 'বিংশ শতাব্দীর অন্যতম প্রধান বাঙালি কবি ও ঔপন্যাসিক সুনীল গঙ্গোপাধ্যায়। ''নীরা'' তাঁর কবিতার এক অমর চরিত্র। উপন্যাসের ক্ষেত্রে ''সেই সময়'', ''প্রথম আলো'' ও ''পূর্ব-পশ্চিম'' তাঁর যুগান্তকারী সৃষ্টি। ১৯৩৪ সালে তৎকালীন অবিভক্ত বাংলার ফরিদপুরে তিনি জন্মগ্রহণ করেন। ২০১২ সালে তিনি মৃত্যুবরণ করেন।', ''),
(5, 'আনিসুল হক', 'বাংলাদেশের সমকালীন সাহিত্যের অন্যতম জনপ্রিয় লেখক, সাংবাদিক ও নাট্যকার আনিসুল হক। তাঁর লেখা ''মা'' উপন্যাসটি বাংলাদেশের মুক্তিযুদ্ধভিত্তিক সাহিত্যের এক অনন্য সংযোজন। তিনি ১৯৬৫ সালে রংপুরে জন্মগ্রহণ করেন এবং বাংলা একাডেমি পুরস্কারসহ নানা স্বীকৃতি অর্জন করেছেন।', ''),
(6, 'শীর্ষেন্দু মুখোপাধ্যায়', 'বাংলা সাহিত্যের অন্যতম জনপ্রিয় কথাসাহিত্যিক শীর্ষেন্দু মুখোপাধ্যায়। তাঁর সৃষ্ট ''শবর দাশগুপ্ত'' ও ''ফটিক'' চরিত্র দুটি বেশ সমাদৃত। মানবজীবনের আধ্যাত্মিকতা ও পরাবাস্তবতা তাঁর লেখার অন্যতম অনুষঙ্গ। ১৯৩৫ সালে ময়মনসিংহে জন্মগ্রহণ করা এই লেখক সাহিত্য আকাদেমি ও বিদ্যাসাগর পুরস্কারে ভূষিত হয়েছেন।', ''),
(7, 'সত্যজিৎ রায়', 'বিশ্ববরেণ্য চলচ্চিত্র নির্মাতা সত্যজিৎ রায় বাংলা সাহিত্যেও এক উজ্জ্বল নক্ষত্র। শিশু-কিশোর সাহিত্যের এক অনন্য কারিগর তিনি। তাঁর সৃষ্টি করা ''ফেলুদা'' এবং ''প্রফেসর শঙ্কু'' চরিত্র দুটি বাংলা সাহিত্যের অন্যতম জনপ্রিয় চরিত্র। ১৯২১ সালে কলকাতায় জন্মগ্রহণ করেন এবং ১৯৯২ সালে প্রয়াত হন।', ''),
(8, 'আহমদ ছফা', 'বাংলাদেশের প্রখ্যাত চিন্তাবিদ, ঔপন্যাসিক ও প্রবন্ধকার আহমদ ছফা। তাঁর ক্ষুরধার লেখনী এবং সমাজ ও রাজনীতির তীক্ষ্ণ বিশ্লেষণের জন্য তিনি ব্যাপকভাবে সমাদৃত। ''ওঙ্কার'', ''গাভী বিত্তান্ত'', ''যদ্যপি আমার গুরু'' তাঁর অমর কীর্তি। ১৯৪৩ সালে চট্টগ্রামের চন্দনাইশে জন্মগ্রহণ করেন এবং ২০০১ সালে তিনি মৃত্যুবরণ করেন।', ''),
(9, 'বিভূতিভূষণ বন্দ্যোপাধ্যায়', 'প্রকৃতি ও গ্রামীণ জীবনের নিপুণ রূপকার বিভূতিভূষণ বন্দ্যোপাধ্যায়। তাঁর লেখা ''পথের পাঁচালী'' ও ''অপরাজিত'' বাংলা সাহিত্যের শ্রেষ্ঠ উপন্যাসের তকমা পেয়েছে। ১৮৯২ সালে পশ্চিমবঙ্গের উত্তর ২৪ পরগনায় তাঁর জন্ম এবং ১৯৫০ সালে তিনি মৃত্যুবরণ করেন।', ''),
(10, 'সৈয়দ শামসুল হক', 'বাংলা সাহিত্যের ''সব্যসাচী লেখক'' হিসেবে পরিচিত সৈয়দ শামসুল হক। ''পায়ের আওয়াজ পাওয়া যায়'', ''নূরলদীনের সারাজীবন'' তাঁর বিখ্যাত কাব্যনাট্য। ১৯৩৫ সালে কুড়িগ্রামে জন্মগ্রহণ করা এই বরেণ্য লেখক ২০১৬ সালে মৃত্যুবরণ করেন।', ''),
(11, 'সাদাত হোসাইন', 'বাংলাদেশের বর্তমান প্রজন্মের অত্যন্ত জনপ্রিয় তরুণ কথাশিল্পী ও নির্মাতা সাদাত হোসাইন। তাঁর লেখনীতে আবেগ, প্রেম ও সামাজিক সম্পর্কের টানাপোড়েন খুব সুন্দরভাবে ফুটে ওঠে। তিনি ১৯৮৪ সালে মাদারীপুরে জন্মগ্রহণ করেন।', ''),
(12, 'তামিম শাহরিয়ার সুবিন', 'বাংলাদেশের তথ্যপ্রযুক্তি ও প্রোগ্রামিং বিষয়ক বইয়ের একজন পথিকৃৎ লেখক। তাঁর লেখা ''কম্পিউটার প্রোগ্রামিং'' বইটি হাজার হাজার তরুণকে প্রোগ্রামিং শিখতে উৎসাহিত করেছে।', ''),
(13, 'কাজী নজরুল ইসলাম', 'বাংলাদেশের জাতীয় কবি কাজী নজরুল ইসলাম, যিনি ''বিদ্রোহী কবি'' নামেও পরিচিত। তাঁর কবিতায় পরাধীনতার বিরুদ্ধে দ্রোহ এবং অসাম্প্রদায়িকতার সুর ধ্বনিত হয়েছে। প্রেম ও দ্রোহের এই কবি ১৮৯৯ সালে চুরুলিয়ায় জন্মগ্রহণ করেন এবং ১৯৭৬ সালে ঢাকায় মৃত্যুবরণ করেন।', ''),
(14, 'হুমায়ূন আজাদ', 'বাংলাদেশের প্রখ্যাত কবি, ঔপন্যাসিক, ভাষাবিজ্ঞানী ও প্রথাবিরোধী চিন্তাবিদ। তাঁর লেখা ''নারী'' বইটি সমাজ, ধর্মান্ধতা ও নারীবাদের এক জোরালো দলিল। ১৯৪৭ সালে বিক্রমপুরের রাড়িখালে জন্মগ্রহণ করেন এবং ২০০৪ সালে জার্মানিতে মৃত্যুবরণ করেন।', ''),
(15, 'জহির রায়হান', 'বাংলাদেশের প্রখ্যাত চলচ্চিত্র পরিচালক, ঔপন্যাসিক এবং গল্পকার জহির রায়হান। ''হাজার বছর ধরে'', ''আরেক ফাল্গুন'', ''বরফ গলা নদী'' তাঁর অমর উপন্যাস। ১৯৩৫ সালে ফেনীতে জন্মগ্রহণ করেন এবং ১৯৭২ সালে নিখোঁজ হন।', ''),
(16, 'ড্যান ব্রাউন', 'বিশ্বনন্দিত মার্কিন থ্রিলার ঔপন্যাসিক ড্যান ব্রাউন। তাঁর সৃষ্ট চরিত্র ''রবার্ট ল্যাংডন'' বিশ্বব্যাপী বিপুল জনপ্রিয়। সাংকেতিক লিপি, শিল্পকলা এবং ইতিহাসকে কেন্দ্র করে তাঁর লেখা বইগুলো বিশ্বব্যাপী বেস্টসেলার। ১৯৬৪ সালে আমেরিকায় তাঁর জন্ম।', ''),
(17, 'চেতন ভগত', 'ভারতের অন্যতম জনপ্রিয় ইংরেজি ভাষার লেখক। তাঁর লেখা বইগুলো মূলত তরুণ সমাজ, প্রেম এবং সমসাময়িক ভারতের নানা সমস্যা ও আকাঙ্ক্ষা নিয়ে রচিত। ১৯৭৪ সালে তিনি নয়াদিল্লিতে জন্মগ্রহণ করেন।', ''),
(18, 'রকিব হাসান', 'বাংলাদেশের শিশু-কিশোর সাহিত্যের অত্যন্ত জনপ্রিয় নাম রকিব হাসান। তিনি মূলত সেবা প্রকাশনীর ''তিন গোয়েন্দা'' সিরিজের স্রষ্টা হিসেবে সর্বাধিক পরিচিত। ১৯৫৩ সালে তিনি কুমিল্লায় জন্মগ্রহণ করেন।', ''),
(19, 'সৈয়দ মুজতবা আলী', 'বাংলা সাহিত্যের অনন্য রম্য রচয়িতা, ভ্রমণকাহিনি লেখক ও বহুভাষাবিদ। ''দেশে বিদেশে'', ''শবনম'', ''পঞ্চতন্ত্র'', ''চাচা কাহিনী'' তাঁর অমর কীর্তি। ১৯০৪ সালে সিলেটে জন্মগ্রহণ করেন এবং ১৯৭৪ সালে তিনি মৃত্যুবরণ করেন।', ''),
(20, 'মানিক বন্দ্যোপাধ্যায়', 'বাংলা সাহিত্যের অন্যতম শক্তিশালী কথাসাহিত্যিক। তাঁর লেখায় মার্কসবাদ ও ফ্রয়েডীয় মনস্তত্ত্বের গভীর প্রভাব দেখা যায়। ''পদ্মানদীর মাঝি'' এবং ''পুতুল নাচের ইতিকথা'' উপন্যাস দুটি বাংলা সাহিত্যের মাস্টারপিস হিসেবে বিবেচিত। ১৯০৮ সালে জন্মগ্রহণ করেন এবং ১৯৫৬ সালে তিনি মৃত্যুবরণ করেন।', ''),
(21, 'বঙ্কিমচন্দ্র চট্টোপাধ্যায়', 'বাংলা উপন্যাসের জনক এবং ''সাহিত্য সম্রাট'' হিসেবে পরিচিত বঙ্কিমচন্দ্র চট্টোপাধ্যায়। তাঁর হাত ধরেই বাংলা উপন্যাস আধুনিক রূপ পায়। ১৮৩৮ সালে নৈহাটির কাঁঠালপাড়ায় জন্মগ্রহণ করেন এবং ১৮৯৪ সালে পরলোকগমন করেন।', ''),
(22, 'আখতারুজ্জামান ইলিয়াস', 'বাংলা সাহিত্যের অন্যতম প্রভাবশালী ও প্রগতিশীল কথাসাহিত্যিক। মাত্র দুটি উপন্যাস—''চিলেকোঠার সেপাই'' এবং ''খোয়াবনামা'' রচনা করেই তিনি বাংলা সাহিত্যে চিরস্থায়ী আসন লাভ করেছেন। ১৯৪৩ সালে গাইবান্ধায় জন্মগ্রহণ করেন এবং ১৯৯৭ সালে মৃত্যুবরণ করেন।', ''),
(23, 'ইমদাদুল হক মিলন', 'বাংলাদেশের সমকালীন কথাসাহিত্যের এক জনপ্রিয় নাম। তাঁর লেখা উপন্যাস ও নাটকগুলো পাঠক এবং দর্শকদের কাছে ব্যাপকভাবে সমাদৃত। ১৯৫৫ সালে বিক্রমপুরে জন্মগ্রহণ করেন।', ''),
(24, 'সেলিনা হোসেন', 'বাংলাদেশের প্রথিতযশা ঔপন্যাসিক ও গল্পকার সেলিনা হোসেন। তাঁর লেখনীতে নারী অধিকার, ভাষা আন্দোলন এবং মুক্তিযুদ্ধ অত্যন্ত স্পষ্টভাবে প্রতিফলিত হয়েছে। ১৯৪৭ সালে রাজশাহীতে জন্মগ্রহণ করেন।', ''),
(25, 'স্টিফেন কিং', 'বিশ্ববিখ্যাত মার্কিন সাহিত্যিক, যিনি হরর, সুপারন্যাচারাল, সাসপেন্স ও সাইকোলজিক্যাল থ্রিলার জনরার ''মুকুটহীন সম্রাট'' হিসেবে পরিচিত। ১৯৪৭ সালে মার্কিন যুক্তরাষ্ট্রে তাঁর জন্ম।', ''),
(26, 'জে. কে. রাওলিং', 'ব্রিটিশ ঔপন্যাসিক, যিনি সর্বকালের অন্যতম জনপ্রিয় ফ্যান্টাসি বইয়ের সিরিজ ''হ্যারি পটার''-এর স্রষ্টা। জাদু, বন্ধুত্ব এবং অন্ধকারের বিরুদ্ধে লড়াই নিয়ে রচিত এই সিরিজটি বিশ্বব্যাপী কোটি কোটি পাঠক তৈরি করেছে। ১৯৬৫ সালে যুক্তরাজ্যে তিনি জন্মগ্রহণ করেন।', ''),
(27, 'কাজী আনোয়ার হোসেন', 'বাংলাদেশের জনপ্রিয় থ্রিলার ও স্পাই সিরিজের জনক এবং ''সেবা প্রকাশনী''-এর প্রতিষ্ঠাতা কাজী আনোয়ার হোসেন। তাঁর সৃষ্ট ''মাসুদ রানা'' এবং ''কুয়াশা'' সিরিজ বাংলাদেশের অগণিত পাঠককে বই পড়ার জগতে আকৃষ্ট করেছে। ১৯৩৬ সালে ঢাকায় জন্মগ্রহণ করেন এবং ২০২২ সালে প্রয়াত হন।', ''),
(28, 'সুমন্ত আসলাম', 'বাংলাদেশের সমকালীন প্রজন্মের একজন জনপ্রিয় লেখক। সহজ, সরল ও আড্ডার ছলে গল্প বলার ধরন তাঁর লেখার অন্যতম বৈশিষ্ট্য।', ''),
(29, 'পাওলো কোয়েলহো', 'ব্রাজিলিয়ান ঔপন্যাসিক ও গীতিকার পাওলো কোয়েলহো বিশ্বজুড়ে এক অনুপ্রেরণামূলক লেখক হিসেবে পরিচিত। তাঁর সর্বশ্রেষ্ঠ কাজ ''দ্য অ্যালকেমিস্ট'' বিশ্বের অন্যতম সর্বাধিক বিক্রীত ও অনূদিত বই। ১৯৪৭ সালে ব্রাজিলের রিও ডি জেনিরোতে তিনি জন্মগ্রহণ করেন।', ''),
(30, 'শওকত ওসমান', 'বাংলাদেশের প্রখ্যাত কথাসাহিত্যিক ও প্রাবন্ধিক শওকত ওসমান। রূপক উপন্যাস ''ক্রীতদাসের হাসি'' এবং ''জননী'', ''বনী আদম'' তাঁর অনবদ্য সাহিত্যকর্ম। ১৯১৭ সালে হুগলিতে তাঁর জন্ম এবং ১৯৯৮ সালে তিনি মৃত্যুবরণ করেন।', '');
